import React from 'react';
import { StatusBadge } from './StatusBadge';

const RequestCard = ({ req, isMine, onClick }) => (
  <div
    onClick={() => onClick(req)}
    style={{
      background: '#fff',
      borderRadius: '18px',
      padding: '24px',
      border: '1px solid #E2E8F0',
      boxShadow: '0 8px 24px rgba(15,23,42,0.06)',
      cursor: 'pointer',
      transition: 'all 0.2s ease'
    }}
  >
    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '16px' }}>
      <div style={{ fontSize: '1.8rem', fontWeight: '800', color: '#1E3A5F' }}>
        {req.requestType}
      </div>
      <StatusBadge status={req.status} />
    </div>

    <div style={{ color: '#64748B', fontSize: '1rem', minHeight: '54px', marginBottom: '18px', lineHeight: 1.6 }}>
      {req.description}
    </div>

    <div style={{ display: 'flex', gap: '20px', color: '#94A3B8', fontSize: '0.95rem', marginBottom: '14px' }}>
      <span>👥 {req.numberOfPeople} người</span>
      <span>
        📅 {req.createdAt ? new Date(req.createdAt).toLocaleDateString('vi-VN') : ''}
      </span>
    </div>

    {isMine && (
      <div style={{ color: '#2563EB', fontWeight: '700', fontSize: '0.95rem' }}>
        YÊU CẦU CỦA BẠN
      </div>
    )}
  </div>
);

export default RequestCard;
